import axios from 'axios';

const API_URL = 'http://localhost:5000/api';

// Create axios instance
const api = axios.create({
  baseURL: API_URL,
  headers: {
    'Content-Type': 'application/json'
  }
});

// Add token to requests if available
api.interceptors.request.use(
  (config) => {
    const token = localStorage.getItem('token');
    if (token) {
      config.headers.Authorization = `Bearer ${token}`;
    }
    return config;
  },
  (error) => {
    return Promise.reject(error);
  }
);

// Auth API calls
export const authAPI = {
  register: (userData) => api.post('/auth/register', userData),
  login: (credentials) => api.post('/auth/login', credentials),
  getProfile: () => api.get('/auth/profile'),
  getDashboard: () => api.get('/auth/dashboard')
};

// Chapters API calls
export const chaptersAPI = {
  getAll: () => api.get('/chapters'),
  getById: (id) => api.get(`/chapters/${id}`),
  getLesson: (chapterId, lessonId) => api.get(`/chapters/${chapterId}/lessons/${lessonId}`),
  create: (chapterData) => api.post('/chapters', chapterData),
  update: (id, chapterData) => api.put(`/chapters/${id}`, chapterData),
  delete: (id) => api.delete(`/chapters/${id}`)
};

// Practice API calls
export const practiceAPI = {
  getAll: () => api.get('/practice'),
  getById: (id) => api.get(`/practice/${id}`),
  getByNumber: (number) => api.get(`/practice/session/${number}`),
  create: (sessionData) => api.post('/practice', sessionData),
  update: (id, sessionData) => api.put(`/practice/${id}`, sessionData),
  delete: (id) => api.delete(`/practice/${id}`)
};

// Progress API calls
export const progressAPI = {
  submitLesson: (progressData) => api.post('/progress/lesson', progressData),
  submitPractice: (progressData) => api.post('/progress/practice', progressData),
  getLessonProgress: () => api.get('/progress/lessons'),
  getPracticeProgress: () => api.get('/progress/practice'),
  getSpecificLesson: (chapterId, lessonId) => api.get(`/progress/lesson/${chapterId}/${lessonId}`)
};

export default api;
